"use strict";exports.id=245,exports.ids=[245],exports.modules={5245:a=>{a.exports=JSON.parse('{"meta":{"title":"WordPing — 더 스마트하게 영어 배우기","description":"AI 번역, 아름다운 테마, 매일 알림을 갖춘 진지한 영어 학습자를 위한 스마트 플래시카드 앱."},"nav":{"features":"기능","howItWorks":"사용법","download":"다운로드"},"hero":{"badge":"iOS에서 이용 가능","title":"영어 완성,\\n한 단어씩.","subtitle":"WordPing은 AI 번역, 아름다운 테마, 매일 알림을 갖춘 스마트 플래시카드 앱입니다. 진지하게 배우는 사람을 위해 만들어졌습니다.","ctaNote":"무료 다운로드"},"features":{"badge":"기능","title":"학습에 필요한 모든 것","subtitle":"간단한 도구, 강력한 결과.","cards":{"flashcards":{"title":"스마트 플래시카드","desc":"카드를 스와이프하고, 뒤집어서 뜻을 확인하고, 폴더로 정리하세요. 나만의 속도로 학습합니다."},"ai":{"title":"AI 자동 번역","desc":"어떤 단어든 즉시 문맥에 맞는 정의를 AI가 제공합니다. 직접 찾아볼 필요가 없습니다."},"test":{"title":"테스트 모드","desc":"단어 뒤집기, 단어 재배열, 테스트 모드로 기억을 강화하세요."},"notifications":{"title":"매일 알림","desc":"맞춤형 푸시 알림으로 학습 세션을 절대 놓치지 마세요. 작은 습관이 큰 결과를 만듭니다."},"themes":{"title":"아름다운 테마","desc":"Deep Sea부터 Sakura, Night City까지 프리미엄 테마로 학습 환경을 꾸며보세요."},"folders":{"title":"정리하고 집중하기","desc":"주제, 챕터, 난이도별로 단어를 폴더에 묶으세요. 정리된 환경에서 더 스마트하게 공부하세요."}}},"how":{"badge":"사용법","title":"3단계로 시작하기","steps":{"1":{"title":"단어 추가하기","desc":"배우고 싶은 단어나 표현을 저장하세요. 뜻과 메모를 추가하고 폴더로 정리하세요."},"2":{"title":"매일 학습하기","desc":"플래시카드를 넘기고, 테스트를 치르고, 알림으로 복습을 습관화하세요. 꾸준함이 실력을 만듭니다."},"3":{"title":"실력이 느는 것을 경험하기","desc":"단어를 마스터할수록 어휘력이 향상됩니다. 시간이 지날수록 실질적인 성장을 느낄 수 있습니다."}}},"cta":{"title":"오늘부터 학습 시작","subtitle":"무료 다운로드. 프리미엄 테마 이용 가능.","button":"App Store에서 다운로드"},"footer":{"tagline":"진지한 학습자를 위해 만들어졌습니다.","rights":"\xa9 2025 WordPing. All rights reserved."}}')}};